SELECT t.*
FROM (
-- 子查询：先按主键ID正序获取全部消息（雪花ID小=插入早=最早的消息）
SELECT *
FROM ai_chat_message
WHERE session_id = #{sessionId}
AND user_id = #{userId}  
ORDER BY message_id -- 核心：用雪花主键ID保证插入顺序
) t
ORDER BY t.message_id

SELECT COUNT(*)
FROM ai_chat_message
WHERE session_id = #{sessionId}
AND user_id = #{userId}

    SELECT *
    FROM ai_chat_message
    WHERE session_id = #{sessionId}
      AND user_id = #{userId}

      AND message_id < #{minMessageId}

ORDER BY message_id DESC
    LIMIT #{limitNum}

